#include <stdio.h>
#include <stdlib.h>

typedef struct {int a; long long b;} Pair;
int cmp(const void *p1, const void *p2) {
    int x = ((Pair*)p1)->a;
    int y = ((Pair*)p2)->a;
    return (x > y) - (x < y);
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,Q; scanf("%d %d", &N, &Q);
        Pair *arr = (Pair*)malloc(N*sizeof(Pair));
        for(int i=0;i<N;i++) scanf("%d", &arr[i].a);
        for(int i=0;i<N;i++) {int tmp; scanf("%d", &tmp); arr[i].b = tmp;}
        qsort(arr, N, sizeof(Pair), cmp);
        long long *pref = (long long*)malloc((N+1)*sizeof(long long));
        pref[0]=0;
        for(int i=0;i<N;i++) pref[i+1]=pref[i]+arr[i].b;
        for(int i=0;i<Q;i++){
            int X; scanf("%d", &X);
            int l=0, r=N; // upper_bound
            while(l<r){
                int m=(l+r)/2;
                if(arr[m].a<=X) l=m+1; else r=m;
            }
            printf("%lld", pref[l]);
            if(i+1<Q) printf(" ");
        }
        printf("\n");
        free(arr); free(pref);
    }
    return 0;
}

