import java.io.*;
import java.util.*;

public class Main {
    static class Pair {
        int a; long b;
        Pair(int a, long b){this.a=a; this.b=b;}
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int Q = Integer.parseInt(st.nextToken());
            int[] A = new int[N];
            long[] B = new long[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) A[i] = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) B[i] = Long.parseLong(st.nextToken());
            Pair[] arr = new Pair[N];
            for (int i = 0; i < N; i++) arr[i] = new Pair(A[i], B[i]);
            Arrays.sort(arr, Comparator.comparingInt(p -> p.a));
            long[] pref = new long[N+1];
            for (int i = 0; i < N; i++) pref[i+1] = pref[i] + arr[i].b;
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < Q; i++) {
                int X = Integer.parseInt(st.nextToken());
                int pos = upperBound(arr, X);
                out.append(pref[pos]);
                if (i + 1 < Q) out.append(' ');
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
    static int upperBound(Pair[] arr, int X) {
        int l = 0, r = arr.length;
        while (l < r) {
            int m = (l + r) >>> 1;
            if (arr[m].a <= X) l = m + 1; else r = m;
        }
        return l;
    }
}

