const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let output = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const Q = data[idx++];
  const A = data.slice(idx, idx + N); idx += N;
  const B = data.slice(idx, idx + N); idx += N;
  const pairs = [];
  for (let i = 0; i < N; i++) pairs.push([A[i], B[i]]);
  pairs.sort((p1, p2) => p1[0] - p2[0]);
  const pref = new Array(N + 1).fill(0);
  for (let i = 0; i < N; i++) pref[i + 1] = pref[i] + pairs[i][1];
  const As = pairs.map(p => p[0]);
  const answers = [];
  for (let i = 0; i < Q; i++) {
    const X = data[idx++];
    // upper bound
    let l = 0, r = N;
    while (l < r) {
      const m = (l + r) >> 1;
      if (As[m] <= X) l = m + 1; else r = m;
    }
    answers.push(pref[l].toString());
  }
  output.push(answers.join(' '));
}
